import java.net.http.*;
import java.net.URI;

public class Main {
    public static void main(String[] args) {
        // Create a reusable client:
        HttpClient client = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .followRedirects(HttpClient.Redirect.NORMAL)
            .build();

        // Build a request:
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("https://jsonplaceholder.typicode.com/posts/1"))
            .header("Accept", "application/json")
            .GET()
            .build();

        System.out.println("Client created: " + (client != null));
        System.out.println("Request URI: " + request.uri());
        System.out.println("Method: " + request.method());
    }
}

import java.net.http.*;
import java.net.URI;
import java.io.IOException;

public class Main {
    public static void main(String[] args) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();

        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("https://jsonplaceholder.typicode.com/posts/1"))
            .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

        System.out.println("Status: " + response.statusCode());
        System.out.println("Body length: " + response.body().length());
        System.out.println("Has userId: " + response.body().contains("userId"));
    }
}

public class Main {
    // Simple JSON value extractor (no library needed for simple cases):
    static String extractString(String json, String key) {
        String search = "\"" + key + "\":\"";
        int start = json.indexOf(search);
        if (start == -1) return null;
        start += search.length();
        int end = json.indexOf('"', start);
        return json.substring(start, end);
    }

    static int extractInt(String json, String key) {
        String search = "\"" + key + \"\":";
        int start = json.indexOf(search);
        if (start == -1) return -1;
        start += search.length();
        int end = start;
        while (end < json.length() && (Character.isDigit(json.charAt(end)))) end++;
        return Integer.parseInt(json.substring(start, end));
    }

    public static void main(String[] args) {
        String json = "{\"userId\":1,\"id\":1,\"title\":\"sample post\",\"body\":\"hello world\"}";

        System.out.println("id: "     + extractInt(json, "id"));
        System.out.println("userId: " + extractInt(json, "userId"));
        System.out.println("title: "  + extractString(json, "title"));
        System.out.println("body: "   + extractString(json, "body"));
    }
}

import java.net.http.*;
import java.net.URI;
import java.io.IOException;

public class Main {
    public static void main(String[] args) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();

        String jsonBody = "{\"title\":\"Java is awesome\",\"body\":\"Learning HTTP in Java!\",\"userId\":1}";

        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("https://jsonplaceholder.typicode.com/posts"))
            .header("Content-Type", "application/json")
            .POST(HttpRequest.BodyPublishers.ofString(jsonBody))
            .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

        System.out.println("Status: " + response.statusCode());
        System.out.println("Created: " + response.body().contains("id"));
    }
}

import java.net.http.*;
import java.net.URI;
import java.util.concurrent.CompletableFuture;

public class Main {
    public static void main(String[] args) throws Exception {
        HttpClient client = HttpClient.newHttpClient();

        long start = System.currentTimeMillis();

        CompletableFuture<String>[] futures = new CompletableFuture[3];
        for (int i = 1; i <= 3; i++) {
            final int id = i;
            futures[i-1] = client.sendAsync(
                HttpRequest.newBuilder()
                    .uri(URI.create("https://jsonplaceholder.typicode.com/posts/" + id))
                    .build(),
                HttpResponse.BodyHandlers.ofString())
                .thenApply(r -> "Post " + id + ": status=" + r.statusCode());
        }

        CompletableFuture.allOf(futures).join();
        for (var f : futures) System.out.println(f.get());

        System.out.println("Time: <2000ms concurrent");
    }
}
